import { ApiInfo, BehaviorInfo, CommonInfo, ConfigObject, PerformanceInfo, PosInfo } from './type';

declare global {
    interface Window {
        __OSS_MONITOR_SDK_?: OSSMonitorSdk;
    }
}

/**
 * oss 前端监控SDK
 */
export class OSSMonitorSdk {
    private bl: any;

    /**
     * 构造函数
     * @param bl - 探针对象
     */
    constructor(bl: any) {
        this.bl = bl;
    }

    /**
     * 检查监控对象是否存在
     * @param bl - 探针对象
     * @returns 监控对象是否存在的布尔值
     */
    private static checkBlExists(bl: any): boolean {
        if (!bl) {
            console.error('未识别到__bl');
            return false;
        }
        return true;
    }

    /**
     * 重新修改部分配置项
     * @param next - 配置项对象
     */
    setConfig(next: ConfigObject) {
        if (OSSMonitorSdk.checkBlExists(this.bl)) {
            this.bl.setConfig(next);
        }
    }

    /**
     * 上报页面的API调用成功率
     * @param info - API信息
     */
    api(info: ApiInfo) {
        if (OSSMonitorSdk.checkBlExists(this.bl)) {
            this.bl.api(info);
        }
    }

    /**
     * 上报页面中的JS错误或使用者想关注的异常
     * @param error - 错误信息
     * @param pos - 错误位置信息
     */
    error(error: Error, pos?: PosInfo) {
        if (OSSMonitorSdk.checkBlExists(this.bl)) {
            this.bl.error(error, pos);
        }
    }

    /**
     * 自定义上报的日志，通常被用于统计业务中特定事件发生的次数
     * @param key - 日志键名
     * @param value - 日志值
     */
    sum(key: string, value?: number) {
        if (OSSMonitorSdk.checkBlExists(this.bl)) {
            this.bl.sum(key, value);
        }
    }

    /**
     * 自定义上报的日志，通常被用于计算业务中特定事件发生的平均次数或平均值
     * @param key - 日志键名
     * @param value - 日志值
     */
    avg(key: string, value?: number) {
        if (OSSMonitorSdk.checkBlExists(this.bl)) {
            this.bl.avg(key, value);
        }
    }

    /**
     * 上报当前行为队列
     */
    reportBehavior() {
        if (OSSMonitorSdk.checkBlExists(this.bl)) {
            this.bl.reportBehavior();
        }
    }

    /**
     * 上报除默认性能指标外的自定义性能指标
     * @param info - 性能信息
     */
    performance(info: PerformanceInfo) {
        if (OSSMonitorSdk.checkBlExists(this.bl)) {
            window.onload = () => {
                setTimeout(() => {
                    this.bl.performance(info);
                }, 1000); //设置一定的延时，确保默认性能数据采集完成。
            };
        }
    }

    /**
     * 重新设置页面的page name
     * @param page - 页面名称
     * @param sendPv - 是否发送PV
     */
    setPage(page: string, sendPv?: boolean) {
        if (OSSMonitorSdk.checkBlExists(this.bl)) {
            this.bl.setPage(page, sendPv);
        }
    }

    /**
     * 设置公共字段
     * @param common - 公共信息
     */
    setCommonInfo(common: CommonInfo) {
        if (OSSMonitorSdk.checkBlExists(this.bl)) {
            this.bl.setCommonInfo(common);
        }
    }

    /**
     * 在当前行为队列末尾添加一条自定义用户行为
     * @param behaviorInfo - 用户行为信息
     */
    addBehavior(behaviorInfo: BehaviorInfo) {
        if (OSSMonitorSdk.checkBlExists(this.bl)) {
            this.bl.addBehavior(behaviorInfo);
        }
    }
}

